set-variable.value:
@{
    var bodyBytes = context.Request.Body.As<string>(preserveContent: true).Length;
    var promptEst = bodyBytes / 4;

    // Parse max_tokens from request JSON
    var maxTokens = 2048;
    try {
        var body = context.Request.Body.As<Newtonsoft.Json.Linq.JObject>(preserveContent: true);
        var mt = body["max_tokens"];
        if (mt != null) {
            maxTokens = mt.Value<int>();
        } else {
            // Also check max_completion_tokens (newer API versions)
            var mct = body["max_completion_tokens"];
            if (mct != null) {
                maxTokens = mct.Value<int>();
            }
        }
    } catch {
        // If parsing fails, use default
    }

    var completionEst = (int)(maxTokens * 0.5);
    return promptEst + completionEst;
}

@{
    var raw = (string)context.Variables.GetValueOrDefault("ptu-consumed-raw", "0");
    int val = 0;
    int.TryParse(raw, out val);
    return val;
}

@{
    var ptuLimit = (int)context.Variables["model-ptu-tpm"];
    if (ptuLimit <= 0) { return false; }
    return (int)context.Variables["ptu-consumed-estimated"] <= ptuLimit;
}
